import React, { useState } from 'react';
import { FiInfo, FiSend } from 'react-icons/fi';

const initialMessages = [
  {
    from: 'ai',
    text: "Hello! I've analyzed your skill profile. Based on current trends, should we focus on optimizing your <strong>Vector DB</strong> knowledge or <strong>RAG pipeline</strong> implementation today?",
  },
  {
    from: 'user',
    text: "Let's go with RAG pipelines. How does it fit into the scalability roadmap?",
  },
  {
    from: 'ai',
    text: "Great choice! RAG pipelines are central to scalable AI systems. The key steps are: (1) set up a vector DB like Pinecone, (2) build a retrieval layer, (3) connect it to your LLM. Want me to suggest a 2-week learning plan?",
  },
];

const AIMentorChat: React.FC = () => {
  const [messages, setMessages] = useState(initialMessages);
  const [input, setInput] = useState('');

  const handleSend = () => {
    const trimmed = input.trim();
    if (!trimmed) return;

    const userMsg = { from: 'user', text: trimmed };
    const aiMsg = {
      from: 'ai',
      text: `That's a great question about "<em>${trimmed}</em>". Based on your profile, I recommend focusing on practical projects first — building a small prototype is 3x more effective for retention than theory alone.`,
    };

    setMessages((prev) => [...prev, userMsg, aiMsg]);
    setInput('');
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') handleSend();
  };

  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 h-[520px] flex flex-col animate-fadeIn">
      {/* Chat Header */}
      <div className="flex items-center justify-between border-b border-gray-100 pb-4 mb-4">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-full flex items-center justify-center text-gray-900 font-bold text-sm shadow-md">AI</div>
          <div>
            <div className="font-bold text-gray-900">Skill Mentor Pro</div>
            <div className="text-xs text-green-500 flex items-center gap-1">
              <span className="w-2 h-2 bg-green-500 rounded-full inline-block"></span> Online
            </div>
          </div>
        </div>
        <button className="text-gray-400 hover:text-gray-600 transition-colors" title="About Mentor">
          <FiInfo size={18} />
        </button>
      </div>

      {/* Messages */}
      <div className="flex-grow space-y-3 overflow-y-auto mb-4 pr-1 scrollbar-thin scrollbar-thumb-gray-200">
        {messages.map((msg, i) => (
          <div
            key={i}
            className={`flex ${msg.from === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[80%] px-4 py-3 rounded-2xl text-sm leading-relaxed ${
                msg.from === 'ai'
                  ? 'bg-blue-50 text-blue-900 rounded-tl-none'
                  : 'bg-gray-100 text-gray-800 rounded-tr-none'
              }`}
              dangerouslySetInnerHTML={{ __html: msg.text }}
            />
          </div>
        ))}
      </div>

      {/* Input */}
      <div className="flex gap-2 items-center">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Ask your mentor anything..."
          className="flex-grow p-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none text-sm transition-all"
        />
        <button
          onClick={handleSend}
          disabled={!input.trim()}
          className="bg-blue-600 text-gray-900 p-3 rounded-xl font-bold hover:bg-blue-700 transition-colors disabled:opacity-40 disabled:cursor-not-allowed"
          title="Send"
        >
          <FiSend size={18} />
        </button>
      </div>
    </div>
  );
};

export default AIMentorChat;
